public class AbstractSealed {
    abstract static class Vehicle {
        abstract int speed();
        String describe() { return getClass().getSimpleName() + "@" + speed(); }
    }
    static class Car extends Vehicle { int speed() { return 120; } }
    static class Bike extends Vehicle { int speed() { return 30; } }
    public static void main(String[] args) {
        Vehicle[] v = {new Car(), new Bike()};
        for (Vehicle x : v) System.out.println(x.describe());
    }
}
